import React from 'react';
import { Check, Trash2, Flame, Zap, Bell, Plus } from 'lucide-react';
import { Habit, Category } from '../types';

interface HabitTrackerProps {
  habits: Habit[];
  completedHabitIds: string[];
  onToggleHabit: (id: string) => void;
  onDeleteHabit: (id: string) => void;
}

export const HabitTracker: React.FC<HabitTrackerProps> = ({ 
  habits, 
  completedHabitIds, 
  onToggleHabit,
  onDeleteHabit
}) => {

  const getCategoryTheme = (cat: Category) => {
    switch(cat) {
      case Category.HEALTH: return { color: 'text-emerald-600 dark:text-emerald-400', bg: 'bg-emerald-50 dark:bg-emerald-400/10', border: 'border-emerald-100 dark:border-emerald-400/20' };
      case Category.WORK: return { color: 'text-blue-600 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-400/10', border: 'border-blue-100 dark:border-blue-400/20' };
      case Category.LEARNING: return { color: 'text-amber-600 dark:text-amber-400', bg: 'bg-amber-50 dark:bg-amber-400/10', border: 'border-amber-100 dark:border-amber-400/20' };
      case Category.MINDFULNESS: return { color: 'text-purple-600 dark:text-purple-400', bg: 'bg-purple-50 dark:bg-purple-400/10', border: 'border-purple-100 dark:border-purple-400/20' };
      default: return { color: 'text-slate-600 dark:text-slate-400', bg: 'bg-slate-50 dark:bg-slate-400/10', border: 'border-slate-100 dark:border-slate-400/20' };
    }
  };

  if (habits.length === 0) {
    return (
      <div className="text-center py-20 px-4 bg-white dark:bg-slate-900 rounded-[2rem] border border-dashed border-slate-300 dark:border-slate-700 transition-colors">
        <div className="w-16 h-16 bg-slate-50 dark:bg-slate-800 rounded-2xl flex items-center justify-center mx-auto mb-4">
          <Zap size={28} className="text-slate-400 dark:text-slate-600" />
        </div>
        <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-2">The canvas is empty</h3>
        <p className="text-slate-500 dark:text-slate-400 max-w-xs mx-auto">Start architecting your routines by adding your first habit.</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      {habits.map((habit, index) => {
        const isCompleted = completedHabitIds.includes(habit.id);
        const theme = getCategoryTheme(habit.category);

        return (
          <div 
            key={habit.id}
            style={{ animationDelay: `${index * 50}ms` }}
            className={`group bg-white dark:bg-slate-900 p-6 rounded-[2rem] border transition-all duration-300 flex flex-col justify-between ${
              isCompleted 
                ? 'opacity-60 border-emerald-200 dark:border-emerald-500/40' 
                : 'border-slate-200 dark:border-slate-800 hover:border-violet-400 dark:hover:border-violet-600 hover:shadow-xl dark:hover:shadow-none'
            }`}
          >
            <div className="flex justify-between items-start mb-6">
              <div className="flex gap-4 min-w-0">
                <button
                  onClick={() => onToggleHabit(habit.id)}
                  aria-label={isCompleted ? "Mark habit as incomplete" : "Mark habit as complete"}
                  className={`flex-shrink-0 h-14 w-14 rounded-2xl flex items-center justify-center transition-all duration-500 border-2 relative group/btn ${
                    isCompleted
                      ? 'bg-emerald-500 border-emerald-400 text-white shadow-lg shadow-emerald-200 dark:shadow-none'
                      : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-400 dark:text-slate-500 hover:border-violet-400 dark:hover:border-violet-500'
                  }`}
                >
                  {/* The visible checkmark when completed */}
                  <Check 
                    size={28} 
                    strokeWidth={4} 
                    className={`transition-all duration-500 ${isCompleted ? 'scale-100 opacity-100' : 'scale-50 opacity-0'}`} 
                  />

                  {/* The "ghost" checkmark on hover when uncompleted */}
                  {!isCompleted && (
                    <Check 
                      size={28} 
                      strokeWidth={4} 
                      className="absolute opacity-0 group-hover/btn:opacity-20 transition-opacity text-violet-600 dark:text-violet-400" 
                    />
                  )}

                  {/* Accessible "indicator" for empty state if needed, but the border usually suffices */}
                </button>

                <div className="min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <h4 className={`font-black text-lg truncate transition-all ${isCompleted ? 'text-slate-400 dark:text-slate-500 line-through' : 'text-slate-900 dark:text-white'}`}>
                      {habit.title}
                    </h4>
                    {habit.streak > 0 && (
                      <div className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-orange-100 dark:bg-orange-500/20 text-orange-600 dark:text-orange-400 text-[10px] font-black uppercase tracking-tighter">
                        <Flame size={10} fill="currentColor" />
                        {habit.streak}
                      </div>
                    )}
                  </div>
                  <div className="flex items-center gap-2">
                    <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md ${theme.bg} ${theme.color} border ${theme.border}`}>
                      {theme.color ? habit.category : Category.OTHER}
                    </span>
                    {habit.reminderTime && (
                       <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 flex items-center gap-1">
                        <Bell size={10} /> {habit.reminderTime}
                      </span>
                    )}
                  </div>
                </div>
              </div>

              <button 
                onClick={() => onDeleteHabit(habit.id)}
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 transition-all"
              >
                <Trash2 size={16} />
              </button>
            </div>

            <div className="flex items-center justify-between mt-auto">
               <div className="flex gap-1">
                  {[...Array(5)].map((_, i) => (
                    <div key={i} className={`w-1.5 h-4 rounded-full ${i < (habit.streak % 5 || (habit.streak > 0 ? 5 : 0)) ? 'bg-violet-600 dark:bg-violet-500' : 'bg-slate-100 dark:bg-slate-800'}`}></div>
                  ))}
               </div>
               <div className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">
                  {habit.frequency} Routine
               </div>
            </div>
          </div>
        );
      })}
    </div>
  );
};

import React, { useState } from 'react';
import { Mail, ArrowRight, Loader2, Layout, AlertCircle, KeyRound, CheckCircle2, User as UserIcon, RotateCcw, ArrowLeft, ShieldCheck } from 'lucide-react';
import { supabase, isSupabaseConfigured } from '../services/supabaseClient';
import { User } from '../types';

interface AuthScreenProps {
  onAuthSuccess: (user: User) => void;
}

export const AuthScreen: React.FC<AuthScreenProps> = ({ onAuthSuccess }) => {
  const [step, setStep] = useState<'email' | 'otp'>('email');
  const [mode, setMode] = useState<'login' | 'signup'>('login');

  const [email, setEmail] = useState('');
  const [name, setName] = useState('');
  const [otp, setOtp] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resendTimer, setResendTimer] = useState(0);

  const isTestAccount = email.toLowerCase() === 'test@test.com';

  const handleGoogleSignIn = async () => {
    setError(null);
    if (!isSupabaseConfigured() || !supabase) {
      setError("System connection missing. Please contact support.");
      return;
    }

    try {
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: {
          redirectTo: window.location.origin,
        },
      });
      if (error) throw error;
    } catch (err: any) {
      console.error("Google Auth Error:", err);
      setError(err.message || "Failed to initialize Google login.");
    }
  };

  const handleSendCode = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    setLoading(true);
    setError(null);

    // Bypass for test account
    if (isTestAccount) {
        setTimeout(() => {
            setStep('otp');
            setLoading(false);
        }, 500);
        return;
    }

    if (!isSupabaseConfigured() || !supabase) {
        setError("System connection missing.");
        setLoading(false);
        return;
    }

    try {
      const { error } = await supabase.auth.signInWithOtp({
        email,
        options: {
          shouldCreateUser: mode === 'signup',
          data: mode === 'signup' ? { full_name: name } : undefined,
        },
      });

      if (error) throw error;

      setStep('otp'); 
      setResendTimer(30);
      const timer = setInterval(() => {
        setResendTimer((prev) => {
          if (prev <= 1) clearInterval(timer);
          return prev - 1;
        });
      }, 1000);

    } catch (err: any) {
      console.error("Auth Error:", err);
      setError(err.message || "Failed to send code. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyCode = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    // Bypass for test account
    if (isTestAccount) {
        setTimeout(() => {
            onAuthSuccess({
                id: '00000000-0000-0000-0000-000000000000', // Hardcoded Test ID
                email: 'test@test.com',
                name: 'Test Architect'
            });
            setLoading(false);
        }, 500);
        return;
    }

    if (!supabase) return;

    try {
      let data, error;
      const types = ['signup', 'magiclink', 'email'] as const;
      let success = false;

      for (const type of types) {
          const result = await supabase.auth.verifyOtp({
              email,
              token: otp,
              type: type as any,
          });

          if (!result.error && result.data?.user) {
              data = result.data;
              success = true;
              break; 
          }
          if (result.error) error = result.error;
      }

      if (!success && error) throw error;

      if (data?.user) {
        onAuthSuccess({
            id: data.user.id,
            email: data.user.email || '',
            name: data.user.user_metadata?.full_name || name || email.split('@')[0] || 'Architect'
        });
      }
    } catch (err: any) {
      console.error("Verification Error:", err);
      setError("Invalid code. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 p-6 font-sans relative overflow-hidden">
      <div className="bg-white w-full max-w-md p-10 rounded-[2.5rem] shadow-2xl border border-slate-200 relative z-10">

        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-violet-600 rounded-2xl shadow-xl shadow-violet-100 mb-6">
            <Layout className="text-white" size={32} />
          </div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight mb-2 uppercase">
            Habit<span className="text-violet-600">Architect</span>
          </h1>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Structural Engineering for Life</p>
        </div>

        {error && (
          <div className="mb-8 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-start gap-3">
            <AlertCircle className="text-rose-600 shrink-0 mt-0.5" size={18} />
            <p className="text-sm text-rose-700 font-bold leading-tight">{error}</p>
          </div>
        )}

        {step === 'email' ? (
          <div className="space-y-6">
            {/* Google Social Login */}
            <button
              onClick={handleGoogleSignIn}
              className="w-full flex items-center justify-center gap-4 bg-white border-2 border-slate-200 py-4 rounded-2xl font-black text-slate-900 hover:bg-slate-50 hover:border-slate-300 transition-all active:scale-[0.98] shadow-sm"
            >
              <svg width="24" height="24" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" fill="#FBBC05"/>
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
              </svg>
              Continue with Google
            </button>

            <div className="relative flex items-center justify-center py-2">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-slate-200"></div>
              </div>
              <span className="relative px-4 bg-white text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">Or use Email</span>
            </div>

            <form onSubmit={handleSendCode} className="space-y-6">
              <div className="flex bg-slate-100 p-1.5 rounded-[1.25rem] border border-slate-200">
                  <button
                      type="button"
                      onClick={() => { setMode('login'); setError(null); }}
                      className={`flex-1 py-2.5 text-sm font-black rounded-xl transition-all ${mode === 'login' ? 'bg-white text-violet-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                      LOG IN
                  </button>
                  <button
                      type="button"
                      onClick={() => { setMode('signup'); setError(null); }}
                      className={`flex-1 py-2.5 text-sm font-black rounded-xl transition-all ${mode === 'signup' ? 'bg-white text-violet-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                      SIGN UP
                  </button>
              </div>

              {mode === 'signup' && (
                  <div className="animate-in slide-in-from-top-2">
                      <label className="block text-[10px] font-black text-slate-400 mb-2 ml-1 uppercase tracking-widest">Full Name</label>
                      <div className="relative">
                          <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400">
                              <UserIcon size={20} />
                          </div>
                          <input
                              type="text"
                              required
                              value={name}
                              onChange={(e) => setName(e.target.value)}
                              className="w-full pl-14 pr-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:bg-white focus:border-violet-600 outline-none transition-all font-bold text-slate-900"
                              placeholder="Your Name"
                          />
                      </div>
                  </div>
              )}

              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-2 ml-1 uppercase tracking-widest">Email Address</label>
                <div className="relative">
                  <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400">
                    <Mail size={20} />
                  </div>
                  <input
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-14 pr-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:bg-white focus:border-violet-600 outline-none transition-all font-bold text-slate-900"
                    placeholder="email@example.com"
                  />
                </div>
              </div>

              <button
                type="submit"
                disabled={loading}
                className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg shadow-xl hover:bg-slate-800 transition-all active:scale-[0.98] flex items-center justify-center gap-3 disabled:opacity-70"
              >
                {loading ? <Loader2 className="animate-spin" size={24} /> : (
                  <>
                    {mode === 'signup' ? 'ESTABLISH ACCOUNT' : 'SEND ACCESS CODE'}
                    <ArrowRight size={20} />
                  </>
                )}
              </button>
            </form>
          </div>
        ) : (
          <form onSubmit={handleVerifyCode} className="space-y-8 animate-in slide-in-from-right-8">
            <div className="text-center">
                <div className="inline-flex items-center justify-center w-14 h-14 bg-emerald-50 rounded-full text-emerald-600 mb-4 border border-emerald-100">
                    <ShieldCheck size={28} />
                </div>
                <h3 className="text-xl font-black text-slate-900 uppercase">Verify Architecture</h3>
                <p className="text-slate-500 text-sm mt-1 font-bold">Code sent to {email}</p>
                {isTestAccount && <p className="text-[10px] text-violet-600 font-black mt-2 uppercase animate-pulse">Test Mode: Enter any code</p>}
            </div>

            <div>
                <div className="relative">
                    <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400">
                        <KeyRound size={20} />
                    </div>
                    <input
                        type="text"
                        required
                        autoFocus
                        value={otp}
                        onChange={(e) => setOtp(e.target.value.replace(/[^0-9]/g, ''))}
                        className="w-full pl-14 pr-6 py-5 bg-slate-50 border border-slate-200 rounded-2xl focus:bg-white focus:border-violet-600 outline-none transition-all font-mono text-3xl font-black text-slate-900 tracking-[0.5em] text-center"
                        placeholder="••••••"
                        maxLength={6} 
                    />
                </div>
            </div>

            <div className="space-y-4">
                <button
                    type="submit"
                    disabled={loading || (otp.length < 6 && !isTestAccount)}
                    className="w-full py-5 bg-violet-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-violet-200 hover:bg-violet-700 transition-all active:scale-[0.98] flex items-center justify-center gap-3 disabled:opacity-70"
                >
                    {loading ? <Loader2 className="animate-spin" size={24} /> : <>FINALIZE LOGIN <CheckCircle2 size={20} /></>}
                </button>

                <div className="flex items-center justify-between px-2">
                    <button 
                        type="button" 
                        onClick={() => setStep('email')} 
                        className="text-slate-400 hover:text-slate-900 text-[10px] font-black uppercase tracking-widest flex items-center gap-2"
                    >
                        <ArrowLeft size={14} /> Back
                    </button>
                    {!isTestAccount && (
                        <button 
                            type="button"
                            onClick={() => handleSendCode()}
                            disabled={resendTimer > 0 || loading}
                            className="text-violet-600 text-[10px] font-black uppercase tracking-widest hover:text-violet-700 disabled:opacity-40 flex items-center gap-2"
                        >
                        {resendTimer > 0 ? `Retry in ${resendTimer}s` : <><RotateCcw size={14} /> Resend Code</>}
                        </button>
                    )}
                </div>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { Plus, Calendar, Layout, BarChart3, CheckCircle2, Target, Menu, X, Home, ListChecks, PieChart, Activity, RotateCcw, Bell, LogOut, Medal, Sparkles as SparklesIcon, Moon, Sun } from 'lucide-react';
import { format } from 'date-fns';
import { supabase, isSupabaseConfigured } from './services/supabaseClient';

import { Habit, Goal, Category, AppState, Frequency, DailyLog, User, Badge } from './types';
import { AuthScreen } from './components/AuthScreen';
import { LandingPage } from './components/LandingPage';
import { HabitTracker } from './components/HabitTracker';
import { GoalTracker } from './components/GoalTracker';
import { AIOverview } from './components/AIOverview';

const Analytics = lazy(() => import('./components/Analytics').then(module => ({ default: module.Analytics })));
const KairoChat = lazy(() => import('./components/KairoChat').then(module => ({ default: module.KairoChat })));
const Achievements = lazy(() => import('./components/Achievements').then(module => ({ default: module.Achievements })));

import { Modal } from './components/UIComponents';

const getTodayKey = () => format(new Date(), 'yyyy-MM-dd');
const TEST_USER_ID = '00000000-0000-0000-0000-000000000000';
const LOCAL_STORAGE_KEY = 'habit_arch_test_data';

// Map clean URL paths to the actual element IDs in the DOM for scrolling
const PATH_TO_ID: Record<string, string> = {
  '/dashboard': 'root',
  '/routines': 'habits',
  '/milestones': 'goals',
  '/insights': 'analytics',
  '/trophies': 'achievements'
};

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [state, setState] = useState<AppState>({ habits: [], goals: [], logs: {}, earnedBadges: [] });
  const [isLoaded, setIsLoaded] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'saved' | 'saving' | 'error'>('saved');

  // Path Routing State
  const [currentPath, setCurrentPath] = useState(window.location.pathname || '/');

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark' || 
             (!localStorage.getItem('theme') && window.matchMedia('(prefers-color-scheme: dark)').matches);
    }
    return false;
  });

  // Navigation Helper (Path-based)
  const navigateTo = (path: string) => {
    const cleanPath = path.startsWith('/') ? path : `/${path}`;
    window.history.pushState({}, '', cleanPath);
    setCurrentPath(cleanPath);

    const sectionId = PATH_TO_ID[cleanPath];
    if (sectionId) {
      setTimeout(() => {
        const el = document.getElementById(sectionId === 'root' ? 'root-container' : sectionId);
        if (el) el.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    }
  };

  useEffect(() => {
    if (window.location.hash) {
      const cleanPath = window.location.hash.replace('#', '') || '/';
      window.history.replaceState({}, '', cleanPath);
      setCurrentPath(cleanPath);
    }

    const handlePopState = () => setCurrentPath(window.location.pathname || '/');
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const triggerConfetti = (isBig = false) => {
    // @ts-ignore
    if (typeof confetti !== 'undefined') {
      // @ts-ignore
      confetti({
        particleCount: isBig ? 250 : 80,
        spread: isBig ? 120 : 60,
        origin: { y: 0.7 },
        colors: ['#7c3aed', '#6366f1', '#d946ef', '#10b981']
      });
    }
  };

  useEffect(() => {
    const client = supabase;
    if (!isSupabaseConfigured() || !client) { setIsLoaded(true); return; }

    client.auth.getSession().then(({ data: { session } }) => {
        if (session?.user) {
             const userData: User = {
                id: session.user.id,
                email: session.user.email || '',
                name: session.user.user_metadata?.full_name || 'Architect'
            };
            setUser(userData);
            loadUserData(userData);
            if (currentPath === '/login' || currentPath === '/') navigateTo('/dashboard');
        } else { setIsLoaded(true); }
    });

    const { data: { subscription } } = client.auth.onAuthStateChange((_event, session) => {
        if (session?.user) {
             const userData: User = {
                id: session.user.id,
                email: session.user.email || '',
                name: session.user.user_metadata?.full_name || 'Architect'
            };
            setUser(userData);
            loadUserData(userData);
            if (currentPath === '/login' || currentPath === '/') navigateTo('/dashboard');
        } else if (user?.id !== TEST_USER_ID) {
            setUser(null);
            setState({ habits: [], goals: [], logs: {}, earnedBadges: [] });
            setIsLoaded(true);
            if (currentPath !== '/') navigateTo('/');
        }
    });
    return () => subscription.unsubscribe();
  }, [user]);

  const loadUserData = async (userData: User) => {
    if (userData.id === TEST_USER_ID) {
        const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
        if (saved) setState(JSON.parse(saved));
        setIsLoaded(true);
        return;
    }

    const client = supabase; if (!client) return;
    try {
      const { data } = await client.from('user_data').select('content').eq('user_id', userData.id).single();
      if (data?.content) setState(data.content as AppState);
    } finally { setIsLoaded(true); }
  };

  useEffect(() => {
    if (!isLoaded || !user) return;

    const saveData = async () => {
      setSaveStatus('saving');

      if (user.id === TEST_USER_ID) {
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(state));
        setSaveStatus('saved');
        return;
      }

      const client = supabase; if (!client) return;
      try {
        await client.from('user_data').upsert({ user_id: user.id, content: state, updated_at: new Date().toISOString() });
        setSaveStatus('saved');
      } catch { setSaveStatus('error'); }
    };
    const timeoutId = setTimeout(saveData, 2000);
    return () => clearTimeout(timeoutId);
  }, [state, isLoaded, user]);

  const [isHabitModalOpen, setHabitModalOpen] = useState(false);
  const [currentHabitTab, setCurrentHabitTab] = useState<Frequency>(Frequency.DAILY);
  const [isSidebarOpen, setSidebarOpen] = useState(false); 
  const mainRef = useRef<HTMLDivElement>(null);

  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitCategory, setNewHabitCategory] = useState<Category>(Category.OTHER);
  const [newHabitFrequency, setNewHabitFrequency] = useState<Frequency>(Frequency.DAILY);

  const toggleHabit = (id: string) => {
    const todayKey = getTodayKey();
    setState(prev => {
      const currentLog = prev.logs[todayKey] || { date: todayKey, completedHabitIds: [], goalProgress: {} };
      const isCompleted = currentLog.completedHabitIds.includes(id);

      if (!isCompleted) triggerConfetti(false);

      const newCompletedIds = isCompleted 
        ? currentLog.completedHabitIds.filter(hid => hid !== id)
        : [...currentLog.completedHabitIds, id];

      const updatedHabits = prev.habits.map(h => {
        if (h.id === id && h.frequency === Frequency.DAILY) {
            return { ...h, streak: isCompleted ? Math.max(0, h.streak - 1) : h.streak + 1 };
        }
        return h;
      });

      return {
        ...prev,
        habits: updatedHabits,
        logs: { ...prev.logs, [todayKey]: { ...currentLog, completedHabitIds: newCompletedIds } }
      };
    });
  };

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;
    const newHabit: Habit = { id: crypto.randomUUID(), title: newHabitTitle, category: newHabitCategory, createdAt: new Date().toISOString(), streak: 0, frequency: newHabitFrequency };
    setState(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
    setNewHabitTitle(''); setHabitModalOpen(false);
  };

  const deleteHabit = (id: string) => setState(prev => ({ ...prev, habits: prev.habits.filter(h => h.id !== id) }));

  const updateGoalProgress = (id: string, delta: number) => {
    setState(prev => ({
      ...prev,
      goals: prev.goals.map(g => {
        if (g.id === id) {
          const nextVal = Math.max(0, g.current + delta);
          if (nextVal >= g.target && g.current < g.target) triggerConfetti(true);
          return { ...g, current: nextVal };
        }
        return g;
      })
    }));
  };

  if (!isLoaded) return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950">
        <div className="w-16 h-16 border-4 border-violet-200 border-t-violet-600 rounded-full animate-spin"></div>
    </div>
  );

  if (!user && currentPath === '/login') return <AuthScreen onAuthSuccess={(u) => { setUser(u); navigateTo('/dashboard'); }} />;
  if (!user) return <LandingPage onStart={() => navigateTo('/login')} />;

  const todayKey = getTodayKey();
  const todayLog = state.logs[todayKey] || { date: todayKey, completedHabitIds: [], goalProgress: {} };
  const percentage = state.habits.length > 0 ? Math.round((todayLog.completedHabitIds.length / state.habits.length) * 100) : 0;

  return (
    <div id="root-container" className="flex h-screen overflow-hidden font-sans bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
      <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transform transition-transform duration-500 ease-out lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full p-8">
          <div className="flex items-center gap-4 mb-12 cursor-pointer" onClick={() => navigateTo('/')}>
            <div className="bg-violet-600 p-3 rounded-2xl shadow-xl shadow-violet-200 dark:shadow-none">
              <Layout className="text-white" size={24} />
            </div>
            <h1 className="text-2xl font-black tracking-tight text-slate-900 dark:text-white">
              Habit<span className="text-violet-500">Arch.</span>
            </h1>
          </div>
          <nav className="space-y-3 flex-1">
            {[
              { id: 'dashboard', path: '/dashboard', icon: Home, label: 'Vision' },
              { id: 'habits', path: '/routines', icon: ListChecks, label: 'Routines' },
              { id: 'goals', path: '/milestones', icon: Target, label: 'Milestones' },
              { id: 'analytics', path: '/insights', icon: PieChart, label: 'Insights' },
              { id: 'achievements', path: '/trophies', icon: Medal, label: 'Trophies' },
            ].map(item => (
              <button 
                key={item.id}
                onClick={() => { navigateTo(item.path); setSidebarOpen(false); }} 
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl font-bold transition-all text-left ${currentPath === item.path ? 'bg-violet-600 text-white shadow-xl shadow-violet-200 dark:shadow-none scale-[1.02]' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 hover:text-slate-900 dark:hover:text-white'}`}
              >
                <item.icon size={20} strokeWidth={2.5} />
                {item.label}
              </button>
            ))}
          </nav>
          <div className="mt-auto pt-8 border-t border-slate-200 dark:border-slate-800">
              <button onClick={() => { if(user.id === TEST_USER_ID) { setUser(null); navigateTo('/'); } else { supabase?.auth.signOut(); } }} className="flex items-center gap-4 px-5 py-3 text-slate-400 hover:text-rose-600 transition-colors text-sm font-bold w-full">
                  <LogOut size={18} /> Sign Out
              </button>
          </div>
        </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 h-full overflow-hidden relative">
        <header className="h-20 flex items-center justify-between px-8 lg:px-12 z-10 shrink-0 bg-white/50 dark:bg-slate-900/50 backdrop-blur-md border-b border-slate-200 dark:border-slate-800">
            <div className="flex items-center gap-4">
              <button onClick={() => setSidebarOpen(true)} className="lg:hidden p-3 bg-white dark:bg-slate-800 rounded-xl shadow-lg border border-slate-200 dark:border-slate-700">
                  <Menu size={24} className="text-slate-900 dark:text-white" />
              </button>
              <div className="hidden lg:flex items-center gap-4 text-slate-400 dark:text-slate-500 font-bold text-xs uppercase tracking-[0.2em]">
                  <Calendar size={14} />
                  <span>{format(new Date(), 'EEEE, MMMM do')}</span>
              </div>
            </div>
            <div className="flex items-center gap-4">
                <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-3 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:text-violet-600 transition-all">
                  {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
                </button>
                <div className="flex items-center gap-4 bg-white dark:bg-slate-800 px-4 py-2 rounded-2xl border border-slate-200 dark:border-slate-700">
                    <span className="font-bold text-sm text-slate-700 dark:text-slate-200 hidden sm:block">{user.name}</span>
                    <div className="w-10 h-10 bg-violet-600 rounded-xl flex items-center justify-center text-white font-black shadow-lg">
                        {user.name[0]}
                    </div>
                </div>
            </div>
        </header>

        <main ref={mainRef} className="flex-1 overflow-y-auto p-8 lg:p-12 blueprint-grid">
            <div className="max-w-6xl mx-auto space-y-12 pb-20">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-8">
                    <div>
                        <h2 className="text-5xl font-black text-slate-900 dark:text-white tracking-tight leading-tight">
                          Success starts <br/>with <span className="text-violet-600 dark:text-violet-500">consistency.</span>
                        </h2>
                    </div>
                    <button onClick={() => setHabitModalOpen(true)} className="flex items-center gap-3 bg-slate-900 dark:bg-white text-white dark:text-slate-900 px-8 py-4 rounded-[1.5rem] font-black shadow-2xl transition-all hover:scale-105 active:scale-95">
                        <Plus size={20} /> Create Routine
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <MetricCard icon={<CheckCircle2 className="text-emerald-500" size={32}/>} title="Daily Trajectory" value={`${percentage}%`} progress={percentage} color="bg-emerald-500" />
                    <MetricCard icon={<Activity className="text-violet-500" size={32}/>} title="Total Systems" value={state.habits.length.toString()} />
                    <MetricCard icon={<Target className="text-indigo-500" size={32}/>} title="Active North Stars" value={state.goals.length.toString()} />
                </div>

                <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                    <div className="xl:col-span-8 space-y-12">
                        <AIOverview habits={state.habits} goals={state.goals} logs={state.logs} />
                        <section id="habits" className="scroll-mt-28">
                             <div className="flex items-center justify-between mb-8">
                                <h3 className="text-2xl font-black text-slate-900 dark:text-white flex items-center gap-3">
                                  <div className="p-2 bg-violet-500/10 rounded-xl text-violet-500"><ListChecks size={24}/></div>
                                  Today's Blueprint
                                </h3>
                                <div className="flex p-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl">
                                    {[Frequency.DAILY, Frequency.WEEKLY, Frequency.MONTHLY].map((tab) => (
                                    <button
                                        key={tab}
                                        onClick={() => setCurrentHabitTab(tab)}
                                        className={`px-5 py-2 text-xs font-black rounded-xl transition-all uppercase tracking-widest ${currentHabitTab === tab ? 'bg-violet-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
                                    >
                                        {tab}
                                    </button>
                                    ))}
                                </div>
                            </div>
                            <HabitTracker habits={state.habits.filter(h => h.frequency === currentHabitTab)} completedHabitIds={todayLog.completedHabitIds} onToggleHabit={toggleHabit} onDeleteHabit={deleteHabit} />
                        </section>
                        <section id="analytics" className="scroll-mt-28">
                            <Suspense fallback={null}><Analytics habits={state.habits} goals={state.goals} logs={state.logs} /></Suspense>
                        </section>
                    </div>
                    <div className="xl:col-span-4 space-y-10">
                        <section id="goals" className="scroll-mt-28">
                            <h3 className="text-2xl font-black text-slate-900 dark:text-white mb-8 flex items-center gap-3">
                               <div className="p-2 bg-indigo-500/10 rounded-xl text-indigo-500"><Target size={24}/></div>
                               North Stars
                            </h3>
                            <GoalTracker goals={state.goals} onUpdateProgress={updateGoalProgress} onDeleteGoal={(id) => setState(prev => ({...prev, goals: prev.goals.filter(g => g.id !== id)}))} />
                        </section>
                    </div>
                </div>

                <section id="achievements" className="scroll-mt-28 mt-20">
                     <div className="flex items-center justify-between mb-8">
                        <h3 className="text-2xl font-black text-slate-900 dark:text-white flex items-center gap-3">
                           <div className="p-2 bg-amber-500/10 rounded-xl text-amber-500"><Medal size={24}/></div>
                           Architect Badges
                        </h3>
                        <div className="text-xs font-black text-slate-400 uppercase tracking-widest bg-white dark:bg-slate-800 px-4 py-2 rounded-xl border border-slate-200 dark:border-slate-700">
                          {state.earnedBadges.length} / 8 Unlocked
                        </div>
                     </div>
                    <Suspense fallback={null}><Achievements earnedBadgeIds={state.earnedBadges} /></Suspense>
                </section>
            </div>
        </main>
      </div>

      <Suspense fallback={null}><KairoChat habits={state.habits} goals={state.goals} logs={state.logs} /></Suspense>

      <Modal isOpen={isHabitModalOpen} onClose={() => setHabitModalOpen(false)} title="New System">
          <div className="space-y-6">
              <input value={newHabitTitle} onChange={e => setNewHabitTitle(e.target.value)} placeholder="Habit Name..." className="w-full bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl outline-none font-bold text-lg border-2 border-transparent focus:border-violet-600 transition-all text-slate-900 dark:text-white"/>
              <div className="grid grid-cols-2 gap-4">
                  <select value={newHabitCategory} onChange={e => setNewHabitCategory(e.target.value as Category)} className="bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl font-bold text-sm outline-none text-slate-900 dark:text-white border border-transparent focus:border-violet-600">
                      {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                  <select value={newHabitFrequency} onChange={e => setNewHabitFrequency(e.target.value as Frequency)} className="bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl font-bold text-sm outline-none text-slate-900 dark:text-white border border-transparent focus:border-violet-600">
                      {Object.values(Frequency).filter(f => f !== Frequency.ONCE).map(f => <option key={f} value={f}>{f}</option>)}
                  </select>
              </div>
              <button onClick={addHabit} className="w-full bg-violet-600 text-white p-5 rounded-2xl font-black shadow-xl hover:bg-violet-700 transition-all uppercase tracking-widest">ESTABLISH SYSTEM</button>
          </div>
      </Modal>
    </div>
  );
}

